import { Component, HostListener, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormBuilder, FormGroup, FormsModule, ReactiveFormsModule, Validators } from '@angular/forms';
import { Router, RouterModule } from '@angular/router';
import { AuthService } from '../../../core/services/auth.service';
import { ToastService } from '../../../core/services/toast.service';

@Component({
  selector: 'app-login',
  standalone: true,
  imports: [
    CommonModule,
    FormsModule,
    ReactiveFormsModule,
    RouterModule
  ],
  templateUrl: './login.component.html',
  styleUrls: ['./login.component.css']
})
export class LoginComponent {
  private fb = inject(FormBuilder);
  private authService = inject(AuthService);
  private router = inject(Router);
  private toastService = inject(ToastService);

  loginForm: FormGroup = this.fb.group({
    correo: ['', [Validators.required, Validators.email]],
    password: ['', [Validators.required, Validators.minLength(6)]],
    rememberMe: [false]
  });

  hidePassword = true;
  isLoading = false;
  errorMessage = '';

  // Recovery state
  showRecoveryModal = false;
  recoveryEmail = '';
  recoveryToken = '';
  recoveryNewPassword = '';
  recoveryStep = 1; // 1 = request token, 2 = reset password
  recoveryMessage = '';
  recoveryError = '';
  isRecoveryLoading = false;

  openRecoveryModal(): void {
    this.showRecoveryModal = true;
    this.recoveryEmail = '';
    this.recoveryToken = '';
    this.recoveryNewPassword = '';
    this.recoveryStep = 1;
    this.recoveryMessage = '';
    this.recoveryError = '';
    this.isRecoveryLoading = false;
  }

  closeRecoveryModal(): void {
    this.showRecoveryModal = false;
  }

  @HostListener('document:keydown.escape')
  onEscapeKey(): void {
    if (this.showRecoveryModal) {
      this.closeRecoveryModal();
    }
  }

  onRequestToken(): void {
    if (!this.recoveryEmail || !this.recoveryEmail.includes('@')) {
      this.recoveryError = 'Por favor ingrese un correo válido';
      return;
    }
    this.isRecoveryLoading = true;
    this.recoveryError = '';
    this.recoveryMessage = '';

    this.authService.forgotPassword(this.recoveryEmail).subscribe({
      next: (res) => {
        this.isRecoveryLoading = false;
        this.recoveryStep = 2;
        this.recoveryMessage = res.mensaje || 'Se ha enviado un código de recuperación a tu correo.';
      },
      error: (err) => {
        this.isRecoveryLoading = false;
        this.recoveryError = err.error?.message || 'Error al solicitar el código de recuperación. Inténtalo de nuevo.';
      }
    });
  }

  onResetPassword(): void {
    if (!this.recoveryToken) {
      this.recoveryError = 'Por favor ingrese el código de recuperación';
      return;
    }
    if (!this.recoveryNewPassword || this.recoveryNewPassword.length < 6) {
      this.recoveryError = 'La contraseña debe tener al menos 6 caracteres';
      return;
    }
    this.isRecoveryLoading = true;
    this.recoveryError = '';
    this.recoveryMessage = '';

    this.authService.resetPassword(this.recoveryToken, this.recoveryNewPassword).subscribe({
      next: (res) => {
        this.isRecoveryLoading = false;
        this.recoveryMessage = res.mensaje || 'Contraseña restablecida exitosamente.';
        // Clear inputs
        setTimeout(() => {
          this.closeRecoveryModal();
        }, 3000);
      },
      error: (err) => {
        this.isRecoveryLoading = false;
        this.recoveryError = err.error?.message || 'Error al restablecer la contraseña. Verifique su código.';
      }
    });
  }

  autofill(role: 'admin' | 'student'): void {
    if (role === 'admin') {
      this.loginForm.patchValue({
        correo: 'admin@insteip.com',
        password: 'Admin123!'
      });
    } else {
      this.loginForm.patchValue({
        correo: 'juan.perez@insteip.com',
        password: 'Alumno123!'
      });
    }
  }

  onSubmit(): void {
    if (this.loginForm.invalid) {
      this.loginForm.markAllAsTouched();
      return;
    }

    this.isLoading = true;
    this.errorMessage = '';

    const { correo, password } = this.loginForm.value;

    this.authService.login({ correo, password }).subscribe({
      next: (response: any) => {
        this.isLoading = false;
        this.toastService.success('¡Bienvenido al campus virtual INSTEIP!');
        this.router.navigate(['/dashboard']);
      },
      error: (err: any) => {
        this.isLoading = false;
        this.errorMessage = err.error?.message || 'Error al conectar con el servidor. Verifique sus credenciales.';
        this.toastService.error(this.errorMessage, 'Fallo de Autenticación');
      }
    });
  }
}
<div class="login-shell font-body">
  <aside class="brand-panel" aria-hidden="true">
    <div class="brand-backdrop"></div>
    <div class="brand-grid"></div>

    <div class="brand-top">
      <div class="brand-mark">I</div>
      <div>
        <p class="brand-name">INSTEIP</p>
        <p class="brand-subname">Campus Virtual</p>
      </div>
    </div>

    <div class="brand-body">
      <span class="brand-kicker">
        <span class="brand-kicker-dot"></span>
        Formacion profesional certificada
      </span>

      <h1 class="brand-title">
        Un acceso serio para una experiencia
        <span>academica moderna</span>
      </h1>

      <p class="brand-copy">
        Ingresa a tus cursos, materiales y certificados desde una plataforma disenada para acompanarte con claridad, orden y confianza institucional.
      </p>

      <div class="brand-divider"></div>

      <div class="brand-features">
        <article class="feature-card">
          <div class="feature-icon">
            <span class="material-symbols-outlined text-[18px]">play_circle</span>
          </div>
          <div>
            <p class="feature-title">Clases en progreso continuo</p>
            <p class="feature-copy">Tu avance se registra mientras aprendes.</p>
          </div>
        </article>

        <article class="feature-card feature-card--gold">
          <div class="feature-icon feature-icon--gold">
            <span class="material-symbols-outlined text-[18px]">workspace_premium</span>
          </div>
          <div>
            <p class="feature-title">Certificacion validable</p>
            <p class="feature-copy">Emision formal con codigo unico de verificacion.</p>
          </div>
        </article>
      </div>

      <div class="brand-stats">
        <div class="stat-card">
          <strong>+120</strong>
          <span>Alumnos activos</span>
        </div>
        <div class="stat-card stat-card--gold">
          <strong>18</strong>
          <span>Programas vigentes</span>
        </div>
        <div class="brand-status">
          <span class="status-dot"></span>
          Plataforma operativa
        </div>
      </div>
    </div>

    <p class="brand-footer">© 2026 INSTEIP · Formacion y campus virtual</p>
  </aside>

  <main class="form-panel">
    <div class="mobile-brand">
      <div class="brand-mark">I</div>
      <div>
        <p class="brand-name brand-name--light">INSTEIP</p>
        <p class="brand-subname brand-subname--light">Campus Virtual</p>
      </div>
    </div>

    <section class="login-card" aria-labelledby="login-title">
      <header class="login-header">
        <span class="login-badge">
          <span class="material-symbols-outlined text-[14px]">lock</span>
          Acceso seguro
        </span>
        <h2 id="login-title" class="login-title">Iniciar sesion</h2>
        <p class="login-subtitle">
          Accede con tus credenciales institucionales para entrar al campus virtual.
        </p>
      </header>

      <form [formGroup]="loginForm" (ngSubmit)="onSubmit()" class="login-form" novalidate>
        @if (errorMessage) {
          <div class="alert-error" role="alert">
            <span class="material-symbols-outlined text-base shrink-0">error</span>
            <div>
              <span class="block font-bold">No se pudo iniciar sesion</span>
              <span class="block font-normal mt-0.5 opacity-90">{{ errorMessage }}</span>
            </div>
          </div>
        }

        <div class="field-block">
          <label class="field-label" for="email">Correo electronico</label>
          <div class="field-shell">
            <span class="field-icon material-symbols-outlined text-[18px]">mail</span>
            <input
              formControlName="correo"
              class="field-input"
              id="email"
              type="email"
              autocomplete="email"
              placeholder="correo@institucion.com">
          </div>
          @if (loginForm.get('correo')?.hasError('required') && loginForm.get('correo')?.touched) {
            <p class="field-error">
              <span class="material-symbols-outlined text-[12px]">info</span>
              El correo es obligatorio.
            </p>
          }
          @if (loginForm.get('correo')?.hasError('email') && loginForm.get('correo')?.touched) {
            <p class="field-error">
              <span class="material-symbols-outlined text-[12px]">info</span>
              El formato de correo no es valido.
            </p>
          }
        </div>

        <div class="field-block">
          <div class="field-row">
            <label class="field-label field-label--tight" for="password">Contrasena</label>
            <button
              type="button"
              class="link-action"
              (click)="openRecoveryModal()">
              Olvide mi contrasena
            </button>
          </div>

          <div class="field-shell">
            <span class="field-icon material-symbols-outlined text-[18px]">lock</span>
            <input
              formControlName="password"
              class="field-input field-input--password"
              id="password"
              [type]="hidePassword ? 'password' : 'text'"
              autocomplete="current-password"
              placeholder="••••••••">
            <button
              type="button"
              class="field-toggle"
              (click)="hidePassword = !hidePassword"
              [attr.aria-label]="hidePassword ? 'Mostrar contrasena' : 'Ocultar contrasena'">
              <span class="material-symbols-outlined text-[18px]">
                {{ hidePassword ? 'visibility' : 'visibility_off' }}
              </span>
            </button>
          </div>
          @if (loginForm.get('password')?.hasError('required') && loginForm.get('password')?.touched) {
            <p class="field-error">
              <span class="material-symbols-outlined text-[12px]">info</span>
              La contrasena es obligatoria.
            </p>
          }
        </div>

        <label class="remember-row" for="remember-me">
          <input formControlName="rememberMe" id="remember-me" type="checkbox">
          <span>Mantener sesion iniciada</span>
        </label>

        <button
          type="submit"
          class="btn-primary"
          [disabled]="loginForm.invalid || isLoading">
          @if (isLoading) {
            <span class="btn-spinner" aria-hidden="true"></span>
            Verificando acceso...
          } @else {
            <span>Ingresar al campus</span>
            <span class="material-symbols-outlined text-[16px]">arrow_forward</span>
          }
        </button>
      </form>

      <section class="quick-access" aria-label="Acceso rapido de prueba">
        <div class="quick-access-head">
          <span class="quick-access-label">Acceso rapido de prueba</span>
          <span class="quick-access-meta">2 perfiles</span>
        </div>

        <div class="quick-access-grid">
          <button type="button" class="quick-card" (click)="autofill('admin')">
            <span class="material-symbols-outlined quick-card-icon quick-card-icon--primary">admin_panel_settings</span>
            <span class="quick-card-role">Administrador</span>
            <span class="quick-card-mail">admin&#64;insteip.com</span>
          </button>

          <button type="button" class="quick-card quick-card--gold" (click)="autofill('student')">
            <span class="material-symbols-outlined quick-card-icon quick-card-icon--gold">school</span>
            <span class="quick-card-role">Alumno</span>
            <span class="quick-card-mail">juan.perez&#64;insteip.com</span>
          </button>
        </div>
      </section>
    </section>

    <footer class="form-footer">
      <nav class="form-footer-links" aria-label="Enlaces legales">
        <a href="#">Terminos</a>
        <span aria-hidden="true">·</span>
        <a href="#">Privacidad</a>
        <span aria-hidden="true">·</span>
        <a href="#">Soporte</a>
      </nav>
      <p>© 2026 INSTEIP · Campus Virtual</p>
    </footer>
  </main>
</div>

@if (showRecoveryModal) {
  <div
    class="modal-backdrop"
    role="dialog"
    aria-modal="true"
    aria-labelledby="recovery-title"
    (click)="closeRecoveryModal()">
    <div class="modal-card" (click)="$event.stopPropagation()">
      <div class="modal-header">
        <h3 id="recovery-title" class="modal-title">
          <span class="material-symbols-outlined text-[18px] text-primary-container">lock_reset</span>
          Recuperar contrasena
        </h3>
        <button type="button" class="modal-close" (click)="closeRecoveryModal()" aria-label="Cerrar">
          <span class="material-symbols-outlined text-[20px]">close</span>
        </button>
      </div>

      <div class="modal-body">
        @if (recoveryError) {
          <div class="alert-error modal-alert" role="alert">
            <span class="material-symbols-outlined text-base shrink-0">warning</span>
            <span>{{ recoveryError }}</span>
          </div>
        }

        @if (recoveryMessage) {
          <div class="alert-success modal-alert" role="status">
            <span class="material-symbols-outlined text-base shrink-0">check_circle</span>
            <span>{{ recoveryMessage }}</span>
          </div>
        }

        @if (recoveryStep === 1) {
          <div class="modal-stack">
            <p class="modal-copy">
              Ingresa tu correo registrado. Si existe una cuenta asociada, recibirás un codigo temporal de 6 digitos.
            </p>
            <div>
              <label class="field-label" for="recovery-email">Correo electronico</label>
              <input
                id="recovery-email"
                [(ngModel)]="recoveryEmail"
                type="email"
                class="modal-input"
                placeholder="correo@institucion.com"
                autocomplete="email">
            </div>
            <button
              type="button"
              class="btn-primary"
              (click)="onRequestToken()"
              [disabled]="isRecoveryLoading">
              {{ isRecoveryLoading ? 'Enviando...' : 'Enviar codigo' }}
            </button>
          </div>
        }

        @if (recoveryStep === 2) {
          <div class="modal-stack">
            <p class="modal-copy">
              Introduce el codigo recibido y define tu nueva contrasena.
            </p>
            <div>
              <label class="field-label" for="recovery-token">Codigo de recuperacion</label>
              <input
                id="recovery-token"
                [(ngModel)]="recoveryToken"
                type="text"
                class="modal-input modal-input--code"
                placeholder="123456"
                inputmode="numeric">
            </div>
            <div>
              <label class="field-label" for="recovery-password">Nueva contrasena</label>
              <input
                id="recovery-password"
                [(ngModel)]="recoveryNewPassword"
                type="password"
                class="modal-input"
                placeholder="Minimo 6 caracteres"
                autocomplete="new-password">
            </div>
            <button
              type="button"
              class="btn-primary"
              (click)="onResetPassword()"
              [disabled]="isRecoveryLoading">
              {{ isRecoveryLoading ? 'Restableciendo...' : 'Restablecer contrasena' }}
            </button>
          </div>
        }
      </div>
    </div>
  </div>
}
